// Some portions generated by Co-Pilot
"use client";

import React, { useState, useEffect, useRef } from "react";
import { useTranslations } from "next-intl";

type SearchResult = {
  slug: string;
  title: string;
  desc: string;
  locale: string;
};

const DocumentationSearch: React.FC<{ compact?: boolean }> = ({
  compact = false,
}) => {
  const t = useTranslations("DocumentationSearch");
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResult[]>([]);
  const [showResults, setShowResults] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (query.length < 2) {
      setResults([]);
      return;
    }
    fetch(`/api/search?q=${encodeURIComponent(query)}`)
      .then((res) => res.json())
      .then((data) =>
        setResults(
          (data as SearchResult[]).filter(
            (r: SearchResult) => r.locale === "en",
          ),
        ),
      )
      .catch(() => setResults([]));
  }, [query]);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (
        inputRef.current &&
        !inputRef.current.contains(e.target as Node) &&
        !(dropdownRef.current && dropdownRef.current.contains(e.target as Node))
      ) {
        setShowResults(false);
      }
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  return (
    <div className={compact ? "w-full max-w-sm" : "w-full max-w-lg mx-auto"}>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
          <svg
            className="w-3.5 h-3.5 text-gray-500 light:text-gray-400"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
            />
          </svg>
        </div>
        <input
          ref={inputRef}
          type="text"
          className={`w-full rounded-lg pl-9 pr-4 border border-white/10 light:border-gray-300 bg-white/[0.05] light:bg-white text-white light:text-gray-900 placeholder:text-gray-500 light:placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-rose-500/30 focus:border-rose-500/40 light:focus:ring-rose-500/20 light:focus:border-rose-300 transition-colors text-sm ${compact ? "py-1.5" : "py-2.5"}`}
          placeholder={t("placeholder")}
          value={query}
          onChange={(e) => {
            setQuery(e.target.value);
            setShowResults(true);
          }}
          onFocus={() => setShowResults(true)}
        />
        {showResults && results.length > 0 && (
          <div
            ref={dropdownRef}
            id="doc-search-dropdown"
            className="absolute top-full mt-2 left-0 w-full bg-[#1a0a3e] light:bg-white border border-white/10 light:border-gray-200 rounded-xl shadow-2xl z-50 max-h-80 overflow-y-auto"
          >
            {results.map((r, i) => (
              <a
                key={i}
                href={`/${r.slug}`}
                className="block px-4 py-3 hover:bg-white/[0.05] light:hover:bg-rose-50 text-white light:text-gray-900 border-b border-white/[0.05] light:border-gray-100 last:border-b-0 transition-colors"
                onClick={() => setShowResults(false)}
              >
                <div className="font-semibold text-sm">{r.title}</div>
                <div className="text-xs text-gray-400 light:text-gray-500 mt-0.5">
                  {r.desc}
                </div>
              </a>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default DocumentationSearch;
